  1	import * as React from 'react';
  2	import { useGetInternalClusterDetails } from '@odf/core/redux/utils';
  3	import { getCephBlockPoolResource } from '@odf/core/resources';
  4	import { CephFileSystemModel } from '@odf/shared';
  5	import {
  6	  useCustomPrometheusPoll,
  7	  usePrometheusBasePath,
  8	} from '@odf/shared/hooks/custom-prometheus-poll';
  9	import { getName } from '@odf/shared/selectors';
 10	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 11	import { humanizeBinaryBytes, referenceForModel } from '@odf/shared/utils';
 12	import {
 13	  RowProps,
 14	  TableColumn,
 15	  TableData,
 16	  useActiveColumns,
 17	  VirtualizedTable,
 18	  useK8sWatchResources,
 19	  WatchK8sResources,
 20	  WatchK8sResults,
 21	} from '@openshift-console/dynamic-plugin-sdk';
 22	import * as _ from 'lodash-es';
 23	import {
 24	  Card,
 25	  CardBody,
 26	  CardHeader,
 27	  CardTitle,
 28	  Flex,
 29	  Label,
 30	  Popover,
 31	  Skeleton,
 32	} from '@patternfly/react-core';
 33	import { SeverityImportantIcon } from '@patternfly/react-icons';
 34	import {
 35	  ExclamationTriangleIcon,
 36	  ExclamationCircleIcon,
 37	  CheckCircleIcon,
 38	} from '@patternfly/react-icons';
 39	import { sortable } from '@patternfly/react-table';
 40	import { t_global_color_status_warning_default as warningColor } from '@patternfly/react-tokens';
 41	import { t_global_color_status_success_default as successColor } from '@patternfly/react-tokens';
 42	import { t_global_color_status_danger_default as dangerColor } from '@patternfly/react-tokens';
 43	import { PoolType } from '../../../constants';
 44	import {
 45	  POOL_NEAR_FULL_THRESHOLD,
 46	  POOL_FULL_THRESHOLD,
 47	} from '../../../constants';
 48	import { getPoolQuery, StorageDashboardQuery } from '../../../queries';
 49	import {
 50	  StoragePoolKind,
 51	  CephFilesystemKind,
 52	  PoolMetrics,
 53	} from '../../../types';
 54	import {
 55	  getPerPoolMetrics,
 56	  getPoolUtilizationPercentage,
 57	  getStoragePoolsFromBlockPools,
 58	  getStoragePoolsFromFilesystem,
 59	} from '../../../utils';
 60	import { PoolUtilizationPopoverContent } from './PoolUtilizationPopoverContent';
 61	import { StoragePoolTableData } from './types';
 62	
 63	const tableColumnInfo = [
 64	  { className: '', id: 'name' },
 65	  { className: '', id: 'volumeType' },
 66	  { className: '', id: 'usage' },
 67	];
 68	
 69	type CustomData = {
 70	  poolUtilization: PoolMetrics;
 71	  poolRawCapacity: PoolMetrics;
 72	  poolUsedCapacity: PoolMetrics;
 73	};
 74	
 75	const PoolRowRenderer: React.FC<RowProps<StoragePoolTableData, CustomData>> = ({
 76	  obj,
 77	  activeColumnIDs,
 78	}) => {
 79	  const { t } = useCustomTranslation();
 80	
 81	  const Icon = obj.critical ? ExclamationCircleIcon : ExclamationTriangleIcon;
 82	  const iconColor = obj.critical ? dangerColor.value : warningColor.value;
 83	  const poolType = obj.type;
 84	  const volumeType = poolType === PoolType.BLOCK ? t('Block') : t('Filesystem');
 85	
 86	  return (
 87	    <>
 88	      <TableData {...tableColumnInfo[0]} activeColumnIDs={activeColumnIDs}>
 89	        {getName(obj)}
 90	      </TableData>
 91	      <TableData {...tableColumnInfo[1]} activeColumnIDs={activeColumnIDs}>
 92	        <Label
 93	          variant="filled"
 94	          color={poolType === PoolType.BLOCK ? 'blue' : 'green'}
 95	        >
 96	          {volumeType}
 97	        </Label>
 98	      </TableData>
 99	      <TableData {...tableColumnInfo[2]} activeColumnIDs={activeColumnIDs}>
100	        <Popover
101	          aria-label={t('Pool utilization information')}
102	          bodyContent={<PoolUtilizationPopoverContent pool={obj} />}
103	          hasAutoWidth
104	          triggerAction="hover"
105	        >
106	          <Flex
107	            alignItems={{ default: 'alignItemsCenter' }}
108	            spaceItems={{ default: 'spaceItemsSm' }}
109	            className="pf-v5-u-cursor-pointer"
110	          >
111	            <Icon style={{ color: iconColor }} />
112	            <span>
113	              {obj.usedCapacity} ({obj.utilization.toFixed(1)}%)
114	            </span>
115	          </Flex>
116	        </Popover>
117	      </TableData>
118	    </>
119	  );
120	};
121	
122	const getResources = (
123	  namespace: string,
124	  clusterName: string
125	): WatchK8sResources<{ [key: string]: any }> => ({
126	  blockPools: getCephBlockPoolResource(clusterName),
127	  filesystem: {
128	    kind: referenceForModel(CephFileSystemModel),
129	    name: `${clusterName}-cephfilesystem`,
130	    namespace,
131	    isList: false,
132	  },
133	});
134	
135	export const PoolUtilizationCard: React.FC = () => {
136	  const { t } = useCustomTranslation();
137	
138	  const { clusterNamespace: clusterNs, clusterName: ocsClusterName } =
139	    useGetInternalClusterDetails();
140	
141	  const resources = useK8sWatchResources(
142	    ocsClusterName ? getResources(clusterNs, ocsClusterName) : {}
143	  );
144	  const { blockPools, filesystem } = resources as WatchK8sResults<{
145	    blockPools: StoragePoolKind[];
146	    filesystem: CephFilesystemKind;
147	  }>;
148	
149	  const { allPools, poolNames } = React.useMemo(() => {
150	    if (!ocsClusterName) {
151	      return { allPools: [], poolNames: [] };
152	    }
153	
154	    const poolsFromBlock =
155	      blockPools?.loaded && !blockPools?.loadError
156	        ? getStoragePoolsFromBlockPools(blockPools.data)
157	        : [];
158	    const poolsFromFS =
159	      filesystem?.loaded && !filesystem?.loadError && filesystem?.data
160	        ? getStoragePoolsFromFilesystem(filesystem.data)
161	        : [];
162	
163	    const pools = [...poolsFromBlock, ...poolsFromFS];
164	    return {
165	      allPools: pools,
166	      poolNames: pools.map((pool) => getName(pool)),
167	    };
168	  }, [blockPools, filesystem, ocsClusterName]);
169	
170	  const utilizationQuery = poolNames?.length
171	    ? getPoolQuery(
172	        poolNames,
173	        StorageDashboardQuery.POOL_UTILIZATION_PERCENTAGE,
174	        ocsClusterName
175	      )
176	    : '';
177	
178	  const [poolUtilizationData, poolMetricsError, poolMetricsLoaded] =
179	    useCustomPrometheusPoll({
180	      query: utilizationQuery,
181	      endpoint: 'api/v1/query' as any,
182	      basePath: usePrometheusBasePath(),
183	    });
184	
185	  const capacityQuery = poolNames?.length
186	    ? getPoolQuery(
187	        poolNames,
188	        StorageDashboardQuery.POOL_MAX_CAPACITY_AVAILABLE,
189	        ocsClusterName
190	      )
191	    : '';
192	
193	  const [poolCapacityData, poolCapacityError, poolCapacityLoaded] =
194	    useCustomPrometheusPoll({
195	      query: capacityQuery,
196	      endpoint: 'api/v1/query' as any,
197	      basePath: usePrometheusBasePath(),
198	    });
199	
200	  const usedCapacityQuery = poolNames?.length
201	    ? getPoolQuery(
202	        poolNames,
203	        StorageDashboardQuery.POOL_RAW_CAPACITY_USED,
204	        ocsClusterName
205	      )
206	    : '';
207	
208	  const [poolUsedCapacityData, poolUsedCapacityError, poolUsedCapacityLoaded] =
209	    useCustomPrometheusPoll({
210	      query: usedCapacityQuery,
211	      endpoint: 'api/v1/query' as any,
212	      basePath: usePrometheusBasePath(),
213	    });
214	
215	  const poolUtilizationMetrics = getPerPoolMetrics(
216	    poolUtilizationData,
217	    poolMetricsError,
218	    poolMetricsLoaded
219	  );
220	
221	  const poolCapacityMetrics = getPerPoolMetrics(
222	    poolCapacityData,
223	    poolCapacityError,
224	    poolCapacityLoaded
225	  );
226	
227	  const poolUsedCapacityMetrics = getPerPoolMetrics(
228	    poolUsedCapacityData,
229	    poolUsedCapacityError,
230	    poolUsedCapacityLoaded
231	  );
232	
233	  const resourcesLoaded = blockPools?.loaded && filesystem?.loaded;
234	  const resourcesError = blockPools?.loadError || filesystem?.loadError;
235	
236	  const poolsNeedingAttention = React.useMemo(() => {
237	    if (!allPools.length) {
238	      return [];
239	    }
240	
241	    const data = allPools.map((pool) => {
242	      const poolName = getName(pool);
243	      const utilization = getPoolUtilizationPercentage(
244	        poolUtilizationMetrics,
245	        poolName
246	      );
247	      const totalCapacityBytes = poolCapacityMetrics?.[poolName] || 0;
248	      const usedCapacityBytes = poolUsedCapacityMetrics?.[poolName] || 0;
249	
250	      return {
251	        ...pool,
252	        utilization,
253	        usedCapacity: humanizeBinaryBytes(usedCapacityBytes).string,
254	        totalCapacity: humanizeBinaryBytes(totalCapacityBytes).string,
255	        critical: utilization >= POOL_FULL_THRESHOLD,
256	        warning:
257	          utilization >= POOL_NEAR_FULL_THRESHOLD &&
258	          utilization < POOL_FULL_THRESHOLD,
259	      };
260	    });
261	
262	    const needingAttention = data
263	      .filter((pool) => pool.critical || pool.warning)
264	      .sort((a, b) => b.utilization - a.utilization);
265	
266	    return needingAttention;
267	  }, [
268	    allPools,
269	    poolUtilizationMetrics,
270	    poolCapacityMetrics,
271	    poolUsedCapacityMetrics,
272	  ]);
273	
274	  const metricsLoaded =
275	    !poolMetricsLoaded && !poolCapacityLoaded && !poolUsedCapacityLoaded;
276	  const metricsError =
277	    poolMetricsError || poolCapacityError || poolUsedCapacityError;
278	
279	  const loading = !resourcesLoaded || !metricsLoaded;
280	  const error = resourcesError || metricsError;
281	
282	  const tableColumns = React.useMemo<TableColumn<StoragePoolTableData>[]>(
283	    () => [
284	      {
285	        title: t('Name'),
286	        sort: 'metadata.name',
287	        transforms: [sortable],
288	        props: {
289	          className: tableColumnInfo[0].className,
290	        },
291	        id: tableColumnInfo[0].id,
292	      },
293	      {
294	        title: t('Volume type'),
295	        props: {
296	          className: tableColumnInfo[1].className,
297	        },
298	        id: tableColumnInfo[1].id,
299	      },
300	      {
301	        title: t('Used of max available'),
302	        props: {
303	          className: tableColumnInfo[2].className,
304	        },
305	        id: tableColumnInfo[2].id,
306	      },
307	    ],
308	    [t]
309	  );
310	
311	  const [columns] = useActiveColumns({
312	    columns: tableColumns,
313	    showNamespaceOverride: false,
314	    columnManagementID: null,
315	  });
316	
317	  const customData: CustomData = React.useMemo(
318	    () => ({
319	      poolUtilization: poolUtilizationMetrics,
320	      poolRawCapacity: poolCapacityMetrics,
321	      poolUsedCapacity: poolUsedCapacityMetrics,
322	    }),
323	    [poolUtilizationMetrics, poolCapacityMetrics, poolUsedCapacityMetrics]
324	  );
325	
326	  return (
327	    <Card>
328	      <CardHeader>
329	        <CardTitle>{t('Storage pool utilization')}</CardTitle>
330	      </CardHeader>
331	      <CardBody>
332	        {!loading && !error && poolsNeedingAttention.length > 0 && (
333	          <>
334	            <Flex
335	              alignItems={{ default: 'alignItemsCenter' }}
336	              spaceItems={{ default: 'spaceItemsSm' }}
337	              className="pf-v6-u-mb-sm"
338	            >
339	              <SeverityImportantIcon className="pf-v5-u-warning-color-100 pf-v6-u-font-size-lg" />
340	              <span className="pf-v6-u-font-size-2xl pf-v6-u-font-weight-bold pf-v5-u-warning-color-100">
341	                {poolsNeedingAttention.length}
342	              </span>
343	              <span>{t('needs attention')}</span>
344	            </Flex>
345	            <p className="pf-v5-u-color-200 pf-v6-u-mb-md">
346	              {t(
347	                'Pools with usage over {{threshold}}% may require immediate action to prevent issues.',
348	                { threshold: POOL_FULL_THRESHOLD }
349	              )}
350	            </p>
351	            <VirtualizedTable
352	              aria-label={t('Storage pools needing attention')}
353	              columns={columns}
354	              Row={PoolRowRenderer}
355	              data={poolsNeedingAttention}
356	              unfilteredData={poolsNeedingAttention}
357	              loaded={true}
358	              loadError={null}
359	              rowData={customData}
360	            />
361	          </>
362	        )}
363	        {loading && (
364	          <div className="pf-v6-u-text-align-center pf-v6-u-p-xl pf-v5-u-color-200">
365	            <Skeleton
366	              height="40%"
367	              screenreaderText={t('Loading pool utilization...')}
368	            />
369	          </div>
370	        )}
371	        {!loading && !_.isEmpty(error) && (
372	          <div className="pf-v6-u-text-align-center pf-v6-u-p-xl pf-v5-u-danger-color-100">
373	            {t('Error loading pool utilization data')}
374	          </div>
375	        )}
376	        {!loading && !error && poolsNeedingAttention.length === 0 && (
377	          <Flex
378	            direction={{ default: 'column' }}
379	            alignItems={{ default: 'alignItemsCenter' }}
380	            justifyContent={{ default: 'justifyContentCenter' }}
381	            className="pf-v6-u-p-2xl"
382	            style={{ minHeight: '200px' }}
383	          >
384	            <CheckCircleIcon
385	              className="pf-v6-u-mb-md"
386	              style={{ color: successColor.value, fontSize: '3rem' }}
387	            />
388	            <p className="pf-v6-u-font-size-xl pf-v5-u-color-100 pf-v6-u-m-0">
389	              {t('Utilization is good!')}
390	            </p>
391	          </Flex>
392	        )}
393	      </CardBody>
394	    </Card>
395	  );
396	};
397	
398	export default PoolUtilizationCard;

