122	const getResources = (
123	  namespace: string,
124	  clusterName: string
125	): WatchK8sResources<{ [key: string]: any }> => ({
126	  blockPools: getCephBlockPoolResource(clusterName),
127	  filesystem: {
128	    kind: referenceForModel(CephFileSystemModel),
129	    name: `${clusterName}-cephfilesystem`,
130	    namespace,
131	    isList: false,
132	  },
133	});
