246	      );
247	      const totalCapacityBytes = poolCapacityMetrics?.[poolName] || 0;
248	      const usedCapacityBytes = poolUsedCapacityMetrics?.[poolName] || 0;
249	
250	      return {
251	        ...pool,
252	        utilization,
253	        usedCapacity: humanizeBinaryBytes(usedCapacityBytes).string,
254	        totalCapacity: humanizeBinaryBytes(totalCapacityBytes).string,
255	        critical: utilization >= POOL_FULL_THRESHOLD,
256	        warning:
257	          utilization >= POOL_NEAR_FULL_THRESHOLD &&
258	          utilization < POOL_FULL_THRESHOLD,
259	      };
260	    });
261	
262	    const needingAttention = data
263	      .filter((pool) => pool.critical || pool.warning)
264	      .sort((a, b) => b.utilization - a.utilization);
265	
266	    return needingAttention;
267	  }, [
268	    allPools,
269	    poolUtilizationMetrics,
270	    poolCapacityMetrics,
271	    poolUsedCapacityMetrics,
272	  ]);
273	
274	  const metricsLoaded =
275	    !poolMetricsLoaded && !poolCapacityLoaded && !poolUsedCapacityLoaded;
276	  const metricsError =
277	    poolMetricsError || poolCapacityError || poolUsedCapacityError;
278	
279	  const loading = !resourcesLoaded || !metricsLoaded;
280	  const error = resourcesError || metricsError;
281	
282	  const tableColumns = React.useMemo<TableColumn<StoragePoolTableData>[]>(
283	    () => [
284	      {
285	        title: t('Name'),
286	        sort: 'metadata.name',
287	        transforms: [sortable],
288	        props: {
289	          className: tableColumnInfo[0].className,
290	        },
291	        id: tableColumnInfo[0].id,
292	      },
293	      {
294	        title: t('Volume type'),
295	        props: {
296	          className: tableColumnInfo[1].className,
297	        },
298	        id: tableColumnInfo[1].id,
299	      },
300	      {
301	        title: t('Used of max available'),
302	        props: {
303	          className: tableColumnInfo[2].className,
304	        },
305	        id: tableColumnInfo[2].id,
306	      },
307	    ],
308	    [t]
309	  );
310	
311	  const [columns] = useActiveColumns({
312	    columns: tableColumns,
313	    showNamespaceOverride: false,
314	    columnManagementID: null,
315	  });
316	
317	  const customData: CustomData = React.useMemo(
318	    () => ({
319	      poolUtilization: poolUtilizationMetrics,
320	      poolRawCapacity: poolCapacityMetrics,
321	      poolUsedCapacity: poolUsedCapacityMetrics,
322	    }),
323	    [poolUtilizationMetrics, poolCapacityMetrics, poolUsedCapacityMetrics]
324	  );
325	
326	  return (
327	    <Card>
328	      <CardHeader>
329	        <CardTitle>{t('Storage pool utilization')}</CardTitle>
330	      </CardHeader>
331	      <CardBody>
332	        {!loading && !error && poolsNeedingAttention.length > 0 && (
333	          <>
334	            <Flex
335	              alignItems={{ default: 'alignItemsCenter' }}
336	              spaceItems={{ default: 'spaceItemsSm' }}
337	              className="pf-v6-u-mb-sm"
338	            >
339	              <SeverityImportantIcon className="pf-v6-u-icon-color-status-warning pf-v6-u-font-size-lg" />
340	              <span className="pf-v6-u-font-size-2xl pf-v6-u-font-weight-bold pf-v6-u-text-color-status-warning">
341	                {poolsNeedingAttention.length}
342	              </span>
343	              <span>{t('needs attention')}</span>
344	            </Flex>
345	            <p className="pf-v6-u-text-color-subtle pf-v6-u-mb-md">
346	              {t(
347	                'Pools with usage over {{threshold}}% may require immediate action to prevent issues.',
348	                { threshold: POOL_FULL_THRESHOLD }
349	              )}
350	            </p>
351	            <VirtualizedTable
352	              aria-label={t('Storage pools needing attention')}
353	              columns={columns}
354	              Row={PoolRowRenderer}
355	              data={poolsNeedingAttention}
356	              unfilteredData={poolsNeedingAttention}
357	              loaded={true}
358	              loadError={null}
359	              rowData={customData}
360	            />
361	          </>
362	        )}
363	        {loading && (
364	          <div className="pf-v6-u-text-align-center pf-v6-u-p-xl pf-v6-u-text-color-subtle">
365	            <Skeleton
366	              height="40%"
367	              screenreaderText={t('Loading pool utilization...')}
368	            />
369	          </div>
370	        )}
371	        {!loading && !_.isEmpty(error) && (
372	          <div className="pf-v6-u-text-align-center pf-v6-u-p-xl pf-v6-u-text-color-status-danger">
373	            {t('Error loading pool utilization data')}
374	          </div>
375	        )}
376	        {!loading && !error && poolsNeedingAttention.length === 0 && (
377	          <Flex
378	            direction={{ default: 'column' }}
379	            alignItems={{ default: 'alignItemsCenter' }}
380	            justifyContent={{ default: 'justifyContentCenter' }}
381	            className="pf-v6-u-p-2xl"
382	            style={{ minHeight: '200px' }}
383	          >
384	            <CheckCircleIcon
385	              className="pf-v6-u-mb-md"
386	              style={{ color: successColor.value, fontSize: '3rem' }}
387	            />
388	            <p className="pf-v6-u-font-size-xl pf-v6-u-text-color-regular pf-v6-u-m-0">
389	              {t('Utilization is good!')}
390	            </p>
391	          </Flex>
392	        )}
393	      </CardBody>
394	    </Card>
395	  );
396	};
397	
398	export default PoolUtilizationCard;
